import{_ as e,o as a,c as l,a2 as n}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"神乐署","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/temple-of-heaven/shenyue-shu.md","filePath":"landmarks/temple-of-heaven/shenyue-shu.md","lastUpdated":1784720050000}'),r={name:"landmarks/temple-of-heaven/shenyue-shu.md"};function o(i,t,d,s,h,g){return a(),l("div",null,[...t[0]||(t[0]=[n('<h1 id="神乐署" tabindex="-1">神乐署 <a class="header-anchor" href="#神乐署" aria-label="Permalink to &quot;神乐署&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1508060812888-6b7e584e03c8?w=1200&amp;q=80" alt="神乐署"></p><blockquote><p>&quot;八音克谐，中和韶乐。祭天之礼，以乐通天。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>神乐署位于天坛内坛西门内，是<strong>明清两代管理祭天乐舞的皇家音乐机构</strong>，始建于明永乐十八年（1420年），初为道流执掌祭祀乐舞的衙署，清乾隆年间定名&quot;神乐署&quot;，与圜丘、祈年殿、皇穹宇、斋宫并称<strong>天坛五大建筑组群</strong>。</p><p>在中国古代礼制中，&quot;礼&quot;与&quot;乐&quot;从来不可分割：祭天大典的每一个仪节——迎帝、奠玉、献帛、三献、送帝——都配以相应的乐章与佾舞。神乐署正是为此而设：署内供奉神乐观道士（后改为乐舞生），负责演练和执掌祭典所用的<strong>中和韶乐</strong>与八佾之舞。鼎盛时期，署内乐舞生多达两千余人，是名副其实的**&quot;中国古代皇家音乐学院&quot;**。</p><p>如今的神乐署已辟为<strong>中国古代皇家音乐展</strong>场所，系统展示宫廷祭祀音乐、乐器与乐律文化，是天坛内唯一以&quot;听觉遗产&quot;为主题的景点。</p><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><p>神乐署坐西朝东，前后两进殿宇：</p><table tabindex="0"><thead><tr><th style="text-align:left;">建筑</th><th style="text-align:center;">位置</th><th style="text-align:left;">功能</th></tr></thead><tbody><tr><td style="text-align:left;">凝禧殿</td><td style="text-align:center;">前殿</td><td style="text-align:left;">演练、演奏中和韶乐之所</td></tr><tr><td style="text-align:left;">显佑殿</td><td style="text-align:center;">后殿</td><td style="text-align:left;">供奉玄武大帝及诸乐神</td></tr><tr><td style="text-align:left;">东西配殿</td><td style="text-align:center;">两厢</td><td style="text-align:left;">现辟为乐器、乐律陈列展厅</td></tr><tr><td style="text-align:left;">朝向</td><td style="text-align:center;">坐西朝东</td><td style="text-align:left;">与斋宫同为坛内西线建筑</td></tr></tbody></table><h3 id="凝禧殿" tabindex="-1">凝禧殿 <a class="header-anchor" href="#凝禧殿" aria-label="Permalink to &quot;凝禧殿&quot;">​</a></h3><p>凝禧殿面阔五间，殿前设宽阔月台，是<strong>演奏中和韶乐的核心场所</strong>。中和韶乐以&quot;中和&quot;为旨，用钟、磬、琴、瑟、箫、笛、笙、鼓等八音之器合奏，节奏庄重舒缓，一字一音，被乾隆帝誉为&quot;八音克谐，无相夺伦&quot;。如今殿内复原了乐悬（乐器陈列）场景，编钟、编磬依律吕分列东西，肃穆如仪。</p><h3 id="乐器陈列" tabindex="-1">乐器陈列 <a class="header-anchor" href="#乐器陈列" aria-label="Permalink to &quot;乐器陈列&quot;">​</a></h3><p>东西配殿展出中国古代宫廷乐器精品：</p><table tabindex="0"><thead><tr><th style="text-align:left;">乐器</th><th style="text-align:center;">类别</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">编钟</td><td style="text-align:center;">金</td><td style="text-align:left;">青铜钟组，按律吕编列，中和韶乐之首</td></tr><tr><td style="text-align:left;">编磬</td><td style="text-align:center;">石</td><td style="text-align:left;">玉石磬组，与编钟金石相和</td></tr><tr><td style="text-align:left;">琴、瑟</td><td style="text-align:center;">丝</td><td style="text-align:left;">丝弦乐器，雅乐文声之主</td></tr><tr><td style="text-align:left;">箫、笛</td><td style="text-align:center;">竹</td><td style="text-align:left;">管乐器，与笙合奏</td></tr><tr><td style="text-align:left;">建鼓、搏拊</td><td style="text-align:center;">革</td><td style="text-align:left;">节乐之器，掌控乐章起止</td></tr></tbody></table><p>展品按周代以来&quot;八音&quot;分类（金、石、丝、竹、匏、土、革、木）体系呈现，辅以乐律图谱与演奏场景复原，是了解中国古代音乐制度的最佳课堂。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="从道观到皇家音乐学院" tabindex="-1">从道观到皇家音乐学院 <a class="header-anchor" href="#从道观到皇家音乐学院" aria-label="Permalink to &quot;从道观到皇家音乐学院&quot;">​</a></h3><p>明初，祭祀乐舞由道士执掌，此处称&quot;神乐观&quot;。因道流渐生懈弛，清康熙、乾隆年间逐步改由八旗子弟充任乐舞生，并扩建衙署、厘定乐制，<strong>神乐署由此成为编制严密、训练有素的宫廷音乐机构</strong>。祭祀之外，乐舞生日常在此排练起居，署内一度形成&quot;音乐社区&quot;。</p><h3 id="战火与重生" tabindex="-1">战火与重生 <a class="header-anchor" href="#战火与重生" aria-label="Permalink to &quot;战火与重生&quot;">​</a></h3><p>1900年庚子之变，神乐署被占驻、毁坏，此后长期衰落，一度沦为工厂民居。20世纪末以来历经腾退、修缮，2004年正式对外开放为皇家音乐展览区，沉睡百年的凝禧殿重新传出编钟编磬之声。</p><h3 id="中和韶乐的-中和-之道" tabindex="-1">中和韶乐的&quot;中和&quot;之道 <a class="header-anchor" href="#中和韶乐的-中和-之道" aria-label="Permalink to &quot;中和韶乐的&quot;中和&quot;之道&quot;">​</a></h3><p>中和韶乐之名出自《尚书》&quot;八音克谐，无相夺伦，神人以和&quot;。其旋律一字一音、节奏徐缓，不求悦耳而求&quot;中正平和&quot;——在古人看来，唯有不偏不倚的乐声才能上达天听、感通神明。祭天大典中，乐章的起止即是仪节的号令，乐与礼互为表里，缺一不可。</p><h2 id="最佳游览季节" tabindex="-1">最佳游览季节 <a class="header-anchor" href="#最佳游览季节" aria-label="Permalink to &quot;最佳游览季节&quot;">​</a></h2><p>神乐署以室内展陈为主，<strong>四时皆宜</strong>，不受天气影响。若能赶上中和韶乐的现场展演时段，则是最佳&quot;游览季节&quot;——金石之声在凝禧殿内回荡，方不负这座皇家音乐学院的旧名。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ol><li><strong>凝禧殿乐悬复原</strong>：编钟、编磬依古制悬列，直观呈现中和韶乐的乐器编制。</li><li><strong>八音乐器展</strong>：按金、石、丝、竹等八音分类的乐器陈列，体系完整。</li><li><strong>中和韶乐演出</strong>：留意展馆演出时段，现场聆听复原的祭天雅乐（演出时间以当日公告为准）。</li><li><strong>显佑殿乐神供奉</strong>：后殿供奉乐神的独特信仰空间，他处罕见。</li><li><strong>人少清幽</strong>：作为西线景点，神乐署游客稀少，可从容细观。</li><li><strong>礼乐对照</strong>：看完神乐署再走<a href="/beijing-travel-guide/landmarks/temple-of-heaven/danbi-qiao.html">丹陛桥</a>、上圜丘，&quot;乐&quot;与&quot;礼&quot;的空间关系豁然贯通。</li><li><strong>留意匾额楹联</strong>：凝禧殿、显佑殿的匾额题字，是理解&quot;以乐事神&quot;理念的点睛之笔。</li></ol><h2 id="最佳拍照点" tabindex="-1">最佳拍照点 <a class="header-anchor" href="#最佳拍照点" aria-label="Permalink to &quot;最佳拍照点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">机位</th><th style="text-align:left;">画面</th><th style="text-align:left;">建议时间</th></tr></thead><tbody><tr><td style="text-align:left;">凝禧殿月台前</td><td style="text-align:left;">殿宇正面与乐悬陈设</td><td style="text-align:left;">上午顺光</td></tr><tr><td style="text-align:left;">编钟编磬展柜侧方</td><td style="text-align:left;">金石乐器的质感特写</td><td style="text-align:left;">全天（展厅内勿用闪光灯）</td></tr><tr><td style="text-align:left;">院落中轴线</td><td style="text-align:left;">前后殿宇的纵深关系</td><td style="text-align:left;">清晨无人时</td></tr><tr><td style="text-align:left;">西配殿门廊</td><td style="text-align:left;">殿廊光影与匾额</td><td style="text-align:left;">下午斜阳</td></tr></tbody></table><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ol><li><strong>位置</strong>：神乐署在坛内西侧，与<a href="/beijing-travel-guide/landmarks/temple-of-heaven/zhai-gong.html">斋宫</a>同属西线，建议两处连游。</li><li><strong>演出信息</strong>：中和韶乐展演有固定时段，入园后可先至服务处确认当日场次，按演出时间安排游线。</li><li><strong>联票包含</strong>：凭天坛联票入内，无需另购票。</li><li><strong>周一注意</strong>：部分展厅周一闭馆，深度游宜避开周一。</li><li><strong>适合慢看</strong>：乐器展品信息量大，建议预留30分钟以上，对音乐史有兴趣者可停留更久。</li><li><strong>带着问题看</strong>：留意&quot;八音&quot;分类中哪些乐器属于金、石、丝、竹，比照展牌自测，是有趣的入门方式。</li></ol><h2 id="相关景点" tabindex="-1">相关景点 <a class="header-anchor" href="#相关景点" aria-label="Permalink to &quot;相关景点&quot;">​</a></h2><ul><li><a href="/beijing-travel-guide/landmarks/temple-of-heaven/zhai-gong.html">斋宫</a>：同在坛内西线，两处连游最顺路</li><li><a href="/beijing-travel-guide/landmarks/temple-of-heaven/huanqiu-tan.html">圜丘坛</a>：中和韶乐的演奏舞台——冬至祭天典礼现场</li><li><a href="/beijing-travel-guide/landmarks/temple-of-heaven/qinian-dian.html">祈年殿</a>：孟春祈谷大典同样以中和韶乐伴奏</li></ul><hr><p><strong>📍 位置</strong>：天坛内坛西部（西门内） <strong>⏱️ 建议游览</strong>：30-45分钟 <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/temple-of-heaven/">天坛概览</a></p>',35)])])}const q=e(r,[["render",o]]);export{f as __pageData,q as default};
